# Check which businesses have parking or bike parking
import ast

def check_parking(attributes):
    has_business_parking = False
    has_bike_parking = False

    if not attributes or attributes == 'None':
        return False, False

    # Check BikeParking
    if isinstance(attributes, dict) and 'BikeParking' in attributes:
        bike_parking_value = attributes['BikeParking']
        if isinstance(bike_parking_value, str):
            if bike_parking_value.lower() == 'true':
                has_bike_parking = True
        elif isinstance(bike_parking_value, bool):
            if bike_parking_value:
                has_bike_parking = True

    # Check BusinessParking
    if isinstance(attributes, dict) and 'BusinessParking' in attributes:
        business_parking_value = attributes['BusinessParking']
        # Parse the string representation of dict
        try:
            if isinstance(business_parking_value, str) and business_parking_value != 'None':
                # Try to parse the string as dict
                if business_parking_value.startswith('{'):
                    parking_dict = ast.literal_eval(business_parking_value)
                    # Check if any parking type is True
                    for key, value in parking_dict.items():
                        if str(value).lower() == 'true':
                            has_business_parking = True
                            break
        except:
            # If parsing fails, try simple string check
            if 'true' in str(business_parking_value).lower():
                has_business_parking = True

    return has_business_parking, has_bike_parking

# Find businesses with parking
